texttool_globals_dialog_message___other_screen_dialog_message_cid = TextObject(bs_BA="%1 je trenutno aktivan u MMI.\nŽelite li ovdje otvoriti aplikaciju?", cs_CZ="%1 je aktuálně aktivní v MMI.\nChcete zde otevřít aplikaci?", da_DK="%1 p.t. aktiv i MMI.\nVil du åbne appen her?", de_DE="%1 ist aktuell im MMI aktiv.\nMöchtest du die App hier öffnen?", el_GR="O/H/Το %1 είναι τώρα ενεργός/-ή/-ό στο MMI.\nΘέλετε να ανοίξετε εδώ την εφαρμογή;", en_GB="%1 is currently active on the MMI.\nWould you like to open the app here?", es_ES="La aplicación %1 está activa en el MMI.\n¿Desea abrir la App aquí?", fi_FI="%1 on tällä hetkellä aktiivisena MMI:ssä.\nHaluatko avata sovelluksen tähän?", fr_FR="L'application %1 est actuellement utilisée\ndans le MMI.\nSouhaitez-vous ouvrir l'application ici?", hr_HR="Aplikacija %1 trenutačno je aktivna u MMI-ju.\nŽelite li je otvoriti tu?", hu_HU="%1 jelenleg aktív az MMI-ben.\nMeg szeretnéd itt nyitni az alkalmazást?", it_IT="Al momento l'app %1 è attiva nell'MMI.\nAprirla qui?", nl_NL="%1 is momenteel in MMI actief.\nWil je de app hier openen?", no_NO="%1 brukes i MMI nå.\nVil du åpne appen her?", pl_PL="%1 jest obecnie aktywna w MMI.\nCzy chcesz otworzyć aplikację tutaj?", pt_PT="%1 está atualmente ativo no MMI.\nQueres abrir a aplicação aqui?", ro_RO="%1 este momentan activ în MMI.\nDoriţi să deschideţi aici aplicaţia?", ru_RU="%1 в данный момент активно в MMI.\nХотите открыть приложение здесь?", sk_SK="%1 je momentálne aktívny v systéme MMI.\nChcete aplikáciu otvoriť tu?", sl_SI="Aplikacija %1 je trenutno aktivna v sistemu MMI.\nAli želite aplikacijo odpreti tukaj?", sr_RS="%1 je trenutno aktivan u MMI.\nŽelite da otvorite ovde aplikaciju?", sv_SE="%1 är aktiv i MMI.\nVill du öppna appen här?", tr_TR="%1 şu anda MMI'da aktif.\nUygulamayı burada açmak ister misin?", uk_UA="%1 зараз активна в MMI.\nХочете відкрити програму тут?")
texttool_globals_dialog_message___other_screen_dialog_message_pid = TextObject(bs_BA="%1 je trenutno aktivno na MMI displeju\nsuvozača. Želite li ovdje otvoriti aplikaciju?", cs_CZ="%1 je aktuálně aktivní na displeji MMI\nspolujezdce. Chcete zde otevřít aplikaci?", da_DK="%1 p.t. aktiv i MMI-display til\nforsædepassager. Vil du åbne appen her?", de_DE="%1 ist aktuell im MMI Beifahrerdisplay aktiv.\nMöchtest du die App hier öffnen?", el_GR="O/H/Το %1 είναι τώρα ενεργός/-ή/-ό στην\nοθόνη συνοδηγού του MMI.\nΘέλετε να ανοίξετε εδώ την εφαρμογή;", en_GB="%1 is currently active on the MMI front\npassenger display. Would you like to open the app here?", es_ES="La aplicación %1 está activa en la pantalla del\nMMI del acompañante. ¿Desea abrir la App aquí?", fi_FI="%1 on tällä hetkellä aktiivisena MMI:n\netumatkustajan näytössä.\nHaluatko avata sovelluksen tähän?", fr_FR="L'application %1 est actuellement utilisée sur\nl'écran MMI du passager avant. Souhaitez-vous ouvrir\nl'application ici?", hr_HR="Aplikacija %1 trenutačno je aktivna na\nsuvozačevom zaslonu MMI-ja. Želite li je otvoriti tu?", hu_HU="%1 jelenleg aktív az MMI utaskijelzőn.\nMeg szeretnéd itt nyitni az alkalmazást?", it_IT="Al momento l'app %1 è attiva nell'MMI del\ndisplay passeggero anteriore. Aprirla qui?", nl_NL="%1 is momenteel in het MMI-bijrijdersdisplay\nactief. Wil je de app hier openen?", no_NO="%1 brukes på MMI-passasjerdisplayet nå.\nVil du åpne appen her?", pl_PL="%1 jest obecnie aktywna w na ekranie MMI\npasażera. Czy chcesz otworzyć aplikację tutaj?", pt_PT="%1 está atualmente ativo no ecrã do\npassageiro do MMI. Queres abrir a aplicação aqui?", ro_RO="%1 este momentan activ în afişajul MMI\npasager faţă. Doriţi să deschideţi aici aplicaţia?", ru_RU="%1 в данный момент активно на дисплее\nMMI переднего пассажира. Хотите открыть\nприложение здесь?", sk_SK="%1 je momentálne aktívny v systéme MMI na\ndispleji spolujazdca. Chcete aplikáciu otvoriť tu?", sl_SI="Aplikacija %1 je trenutno aktivna na\nsovoznikovem zaslonu sistema MMI.\nAli želite aplikacijo odpreti tukaj?", sr_RS="%1 je trenutno aktivan u MMI.\nŽelite da otvorite ovde aplikaciju?", sv_SE="%1 är aktiv på MMI-passagerardisplayen.\nVill du öppna appen här?", tr_TR="%1 şu anda MMI ön yolcu ekranında aktif.\nUygulamayı burada açmak ister misin?", uk_UA="%1 зараз активна на дисплеї MMI\nпереднього пасажира. Хочете відкрити програму тут?")
texttool_globals_dialog_message___pid_off_or_decorator_dialog_message = TextObject(bs_BA="Želite li na MMI ekranu suvozača preći na dizajn mirovanja ili\nga želite u potpunosti isključiti?", cs_CZ="Chcete přepnout displej spolujezdce MMI do režimu standby\nnebo ho chcete úplně vypnout?", da_DK="Vil du skifte til standbydesign i MMI-displayet til\nforsædepassageren, eller vil du slukke det helt?", de_DE="Möchtest du im MMI Beifahrerdisplay in das Standby-Design\nwechseln oder möchtest du es ganz ausschalten?", el_GR="Θέλετε στην οθόνη MMI του συνοδηγού να μεταβείτε στην\nένδειξη αναμονής ή θέλετε να την απενεργοποιήσετε εντελώς;", en_GB="Would you like to switch to standby design on the MMI\nfront passenger display or would you like to switch it off\ncompletely?", es_ES="¿Desea cambiar la pantalla del MMI del acompañante al\ndiseño standby o desea apagarla del todo?", fi_FI="Haluatko vaihtaa MMI:n etumatkustajan näyttöön\nstandby-ulkoasun vai haluatko kytkeä näytön kokonaan\npois päältä?", fr_FR="Souhaitez-vous activer le design du mode veille sur l'écran\nMMI du passager avant ou souhaitez-vous désactiver\ncomplètement cet écran?", hr_HR="Želite li na MMI zaslonu za suvozača prijeći na standby dizajn\nili ga želite potpuno isključiti?", hu_HU="Standby-Designra váltasz az MMI utaskijelzőjén, vagy\nteljesen kikapcsolod?", it_IT="Mettere in standby l'MMI del display passeggero anteriore o\nspegnerlo completamente?", nl_NL="Wil je overgaan naar het MMI-bijrijdersdisplay in het\nstandby-design of wil je het helemaal uitschakelen?", no_NO="Vil du bytte til standby-design for MMI-passasjerdisplayet,\neller vil du slå det helt av?", pl_PL="Czy chcesz przełączyć ekran pasażera MMI na tryb czuwania,\nczy całkiem go wyłączyć?", pt_PT="Queres mudar para o design standby no ecrã do passageiro\ndo MMI ou queres desligá-lo totalmente?", ro_RO="Doriţi să comutaţi la designul de standby pentru afişajul MMI\nal pasagerului sau doriţi să îl dezactivaţi complet?", ru_RU="Вы хотите переключиться в режим ожидания на дисплее\nпереднего пассажира MMI или полностью выключить его?", sk_SK="Chcete prejsť do pohotovostného režimu na displeji\nspolujazdca systému MMI alebo ho chcete úplne vypnúť?", sl_SI="Ali želite na sovoznikovem zaslonu sistema MMI preklopiti\nna prikaz v stanju pripravljenosti ali ga želite\npopolnoma izključiti?", sr_RS="Da li na MMI displeju suvozača želite preći na standby dizajn\nili ga želite u potpunosti isključiti?", sv_SE="Vill du växla MMI-passagerardisplayen till standby-läget eller\nstänga av den helt?", tr_TR="MMI yolcu ekranında bekleme tasarımına geçmek mi istersin\nyoksa tamamen kapatmak mı istersin?", uk_UA="Ви хочете переключитися в режим очікування на дисплеї\nпереднього пасажира MMI або повністю вимкнути його?")
texttool_globals_dialog_message___reboot_safemode_confirm = TextObject(bs_BA="Želite li pokrenuti osigurani režim? Na taj način se deaktiviraju sve aplikacije trećih\nponuđača koje ste instalirali. Nakon ponovnog pokretanja se iste ponovo\nuspostavljaju.", cs_CZ="Chcete spustit nouzový režim? Tím deaktivujete všechny nainstalované aplikace\ntřetích stran. Po restartu budou obnoveny.", da_DK="Vil du starte den sikrede tilstand? Dermed deaktiveres de apps fra\ntredjepartsudbydere, du har installeret. Efter en ny start genetableres de.", de_DE="Möchtest du den abgesicherten Modus starten? Dadurch werden alle von dir\ninstallierten Drittanbieter-Apps deaktiviert. Nach dem Neustart werden diese\nwiederhergestellt.", el_GR="Θέλετε να εκκινήσετε την προστατευμένη λειτουργία; Αυτή θα απενεργοποιήσει τις\nεγκατεστημένες από εσάς εφαρμογές τρίτων. Μετά την επανεκκίνηση, αυτές θα\nαποκατασταθούν πάλι.", en_GB="Do you want to start safe mode? This will deactivate all third-party apps you have\ninstalled. They will be reactivated after restarting.", es_ES="¿Desea iniciar el modo seguro? Se desactivarán todas las aplicaciones de terceros\nque haya instalado. Cuando arranque el vehículo de nuevo, se restablecerán.", fi_FI="Haluatko käynnistää varmistetun tilan? Sen myötä kaikki asentamasi kolmansien\nosapuolten sovellukset deaktivoidaan. Ne palautetaan uudelleenkäynnistyksen\njälkeen.", fr_FR="Souhaitez-vous lancer le mode sans échec? Cela désactivera toutes les applications\ntierces que vous avez installées. Après le redémarrage, elles seront restaurées.", hr_HR="Želite li pokrenuti sigurni modus? Na taj će se način deaktivirati sve aplikacije trećih\npružatelja usluga koje ste instalirali. Nakon ponovnog pokretanja one će se ponovno\naktivirati.", hu_HU="El szeretnéd indítani a biztosított módot? Ezzel kikapcsolásra kerül az összes\náltalad telepített, harmadik féltől származó alkalmazás. Az újraindítás után ezek\nvisszaállnak.", it_IT="Avviare la modalità provvisoria? In questo modo si disattiveranno tutte le app di\nfornitori terzi installate. Verranno ripristinate dopo il riavvio.", nl_NL="Wil je de beveiligde modus starten? Dan worden alle door jouw geïnstalleerde apps\nvan derden gedeactiveerd. Na opnieuw opstarten worden ze hersteld.", no_NO="Vil du starte sikker modus? Da deaktiveres alle tredjepartsapper du har installert.\nDe gjenopprettes etter omstart.", pl_PL="Czy chcesz uruchomić tryb bezpieczny? Spowoduje to dezaktywację wszystkich\nzainstalowanych aplikacji innych firm. Zostaną one przywrócone po ponownym\nuruchomieniu.", pt_PT="Queres iniciar o modo protegido? Desta forma são desativadas todas as aplicações\nde fornecedores externos por ti instaladas. Após o reinicio estas serão\nrestabelecidas.", ro_RO="Doriţi să porniţi modul protejat? Astfel se dezactivează toate aplicaţiile de la\nfurnizori terţi instalate de dumneavoastră. După repornire, acestea vor fi\nrestabilite.", ru_RU="Хотите запустить безопасный режим? Это приведет к деактивации всех\nустановленных сторонних приложений. Они будут восстановлены после\nперезапуска.", sk_SK="Chcete spustiť zabezpečený režim? Tým sa deaktivujú všetky nainštalované aplikácie\ntretích strán. Po reštarte sa tieto znovu obnovia.", sl_SI="Ali želite zagnati varni način? S tem bodo deaktivirane vse aplikacije tretjih\nponudnikov, ki ste jih namestili. Po ponovnem zagonu bodo znova vzpostavljene.", sr_RS="Želite li da pokrenete obezbeđeni režim? Na taj način se deaktiviraju sve aplikacije\ntrećih ponuđača koje ste instalirali. Nakon novog pokretanja se one ponovo\nuspostavljaju.", sv_SE="Vill du starta säkert läge? Detta avaktiverar alla tredjepartsappar du installerat.\nEfter omstart har de återställts igen.", tr_TR="Güvenli modu başlatmak istiyor musun? Bu şekilde yüklediğin tüm üçüncü taraf\nuygulamaları devre dışı bırakılır. Yeniden başlatıldıktan sonra bunlar geri yüklenir.", uk_UA="Хочете запустити безпечний режим? Це призведе до деактивації всіх\nвстановлених сторонніх програм. Вони будуть відновлені після перезапуску.")
texttool_globals_dialog_message___system_battery_low = TextObject(bs_BA="Uspostavite spremnost za vožnju, inače će se sistem\nuskoro isključiti.", cs_CZ="Vytvořte prosím připravenost k jízdě, jinak se systém brzy vypne.", da_DK="Etabler kørselsparathed, ellers slukkes systemet om kort tid.", de_DE="Bitte stelle die Fahrbereitschaft her, sonst schaltet das\nSystem in Kürze ab.", el_GR="Δημιουργήστε την ετοιμότητα οδήγησης, ειδάλλως το\nσύστημα θα απενεργοποιηθεί σε λίγο.", en_GB="Please activate the drive system, otherwise the system will\nbe switched off shortly.", es_ES="Por favor, establezca la disposición para circular, si no el\nsistema se desconectará en breve.", fi_FI="Muodosta ajovalmius, muuten järjestelmä kytkeytyy\npian pois päältä.", fr_FR="Veuillez établir l'état de marche du véhicule sinon le système\nse désactivera dans quelques instants.", hr_HR="Uspostavite pripravnost za vožnju, inače će se sustav\nubrzo isključiti.", hu_HU="Kérünk, hozd létre a menetkész állapotot, különben a\nrendszer rövidesen kikapcsol.", it_IT="Predisporre la vettura per la marcia, altrimenti il sistema si\nspegnerà tra breve.", nl_NL="Stel rijklaarstand in, anders wordt het systeem zo meteen uitgeschakeld.", no_NO="Sett bilen i kjøreberedskap, ellers vil systemet snart\nbli slått av.", pl_PL="Proszę ustanowić gotowość do jazdy, inaczej system wkrótce się wyłączy.", pt_PT="Por favor, estabelece a disponibilidade de circulação, caso\ncontrário o sistema desligar-se-á em breve.", ro_RO="Realizaţi starea operaţională, în caz contrar, sistemul se\ndezactivează în scurt timp.", ru_RU="Восстановите, пожалуйста, готовность к движению, иначе\nвскоре система отключится.", sk_SK="Prosím, vytvorte pohotovostný stav pre jazdu, inak sa systém\nv krátkej dobe vypne.", sl_SI="Vzpostavite pripravljenost vozila, sicer se bo sistem v kratkem izključil.", sr_RS="Uspostavite spremnost za vožnju, u suprotnom će se sistem uskoro isključiti.", sv_SE="Upprätta körberedskap, annars stängs systemet snart av.", tr_TR="Lütfen aracı sürüşe hazır duruma getir, aksi takdirde sistem\nkısa süre sonra kapanır.", uk_UA="Відновіть готовність до руху, в іншому разі систему через\nдеякий час буде вимкнено.")
texttool_globals_dialog_message___system_energy_deficits = TextObject(bs_BA="Aktivno isključivanje potrošača", cs_CZ="Vypnutí spotřebičů aktivní", da_DK="Forbrugerslukning aktiv", de_DE="Verbraucherabschaltung aktiv", el_GR="Απενεργοποίηση ηλεκτρικών καταναλωτών ενεργή", en_GB="Auxiliary deactivation active", es_ES="Desactivación de consumidores activa", fi_FI="Sähkölaitteiden sammutus aktiivinen", fr_FR="Désactivation des consommateurs activée", hr_HR="Aktivno isključivanje trošila", hu_HU="Fogyasztókikapcsolás aktív", it_IT="Disattivazione utenze attiva", nl_NL="Verbruikeruitschakeling actief", no_NO="Strømforbrukere kobles ut", pl_PL="Wyłączanie odbiorników aktywne", pt_PT="Desativação de consumidores ativa", ro_RO="Dezactivare consumatori activă", ru_RU="Отключение потребителей активно", sk_SK="Odpojenie spotrebičov aktívne", sl_SI="Izklop porabnikov aktiven", sr_RS="Aktivno isključivanje potrošača", sv_SE="Avstängning av förbrukare aktiv", tr_TR="Tüketici kapatma aktif", uk_UA="Вимкнення споживачів активне")
texttool_globals_dialog_message___system_standby = TextObject(bs_BA="Priprema se stanje mirovanja. Postupak se može prekinuti\nupravljanjem u MMI-ju ili uključivanjem vozila.", cs_CZ="Připravuje se klidový stav. Postup můžete přerušit obsluhou\nna MMI nebo zapnutím vozidla.", da_DK="Standbyfunktion forberedes. Proces kan afbrydes via\nbetjening i MMI eller start af bil.", de_DE="Der Ruhezustand wird vorbereitet. Der Vorgang kann durch\nBedienung im MMI oder durch Einschalten des Fahrzeugs\nabgebrochen werden.", el_GR="Γίνεται προετοιμασία της κατάστασης ηρεμίας. Η διαδικασία\nμπορεί να διακοπεί μέσω χειρισμού στο MMI ή ενεργοποίησης\nτου οχήματος.", en_GB="Preparing sleep mode. The procedure can be cancelled by\nusing the MMI or by switching on the vehicle.", es_ES="Preparando el estado de reposo. El proceso se puede\ncancelar manejando el MMI o encendiendo el vehículo.", fi_FI="Lepotilaa valmistellaan. Voit keskeyttää menettelyn\nkäyttämällä MMI-järjestelmää tai kytkemällä auton päälle.", fr_FR="Préparation à la mise en veille. Vous pouvez annuler la\nprocédure en pressant une touche du MMI ou en établissant\nl'alimentation du véhicule.", hr_HR="Priprema se stanje mirovanja. Postupak se može prekinuti\nrukovanjem u MMI-ju ili uključivanjem vozila.", hu_HU="Nyugalmi állapot előkészítése. A folyamat az MMI-ben\ntörténő kezeléssel vagy a jármű bekapcsolásával\nszakítható meg.", it_IT="Preparazione della modalità sleep in corso. L'operazione può\nessere annullata azionando un comando nell'MMI o\naccendendo la vettura.", nl_NL="De standbystand wordt voorbereid. het proces kan door de\nbediening in het MMI of door het inschakelen van het\nvoertuig worden afgebroken.", no_NO="Forbereder hvilemodus. Du kan avbryte prosessen ved å\nbetjene MMI eller slå på bilen.", pl_PL="Trwa przygotowanie stanu spoczynku. Proces można\nanulować przez obsługę w MMI lub włączenie pojazdu.", pt_PT="A preparar o estado de repouso. O procedimento pode ser\ninterrompido no MMI quando se liga o veículo.", ro_RO="Este pregătit regimul de repaos. Procesul poate fi întrerupt\nprin operare în MMI sau prin activarea autovehiculului.", ru_RU="Подготовка режима покоя. Процесс можно прервать с\nпомощью управления в MMI или включением автомобиля.", sk_SK="Pripravuje sa stav kľudu. Proces je možné zrušiť ovládaním v\nsystéme MMI alebo prostredníctvom zapnutia vozidla.", sl_SI="Stanje mirovanja se vzpostavlja. Postopek je mogoče prekiniti\nz upravljanjem v sistemu MMI ali vklopom vozila.", sr_RS="Priprema se stanje mirovanja. Postupak može da se prekine\n upravljanjem u MMI-ju ili uključivanjem vozila.", sv_SE="Viloläget förbereds. Processen kan avbrytas genom att\nanvända MMI eller starta fordonet.", tr_TR="Uyku modu hazırlanıyor. İşlem, MMI'da kullanım ile veya araç\naçılarak iptal edilebilir.", uk_UA="Підготовка до гібернації. Процес можна перервати за\nдопомогою управління в MMI або увімкненням автомобіля.")
